"""Minimal colorclass compatibility shim.

This project only needs plain-text output in the VM terminal, so this module
strips color tags and returns ordinary strings.
"""

from __future__ import annotations

import re

_TAG_RE = re.compile(r"\{/?[A-Za-z0-9_]+\}")


class Color(str):
    """Drop color tags used by colorclass and keep plain text."""

    def __new__(cls, value: object = "") -> "Color":
        text = _TAG_RE.sub("", str(value))
        return str.__new__(cls, text)


class Windows:
    @staticmethod
    def enable(*_args: object, **_kwargs: object) -> None:
        return None


def disable_all_colors(*_args: object, **_kwargs: object) -> None:
    return None

